import{c as o,Q as t,j as a,m as s}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse(`{"title":"@muhaven/mcp — broker daemon","description":"What the broker actually does, and why it's a separate process.","frontmatter":{"title":"@muhaven/mcp — broker daemon","description":"What the broker actually does, and why it's a separate process."},"headers":[],"relativePath":"mcp/broker.md","filePath":"mcp/broker.md","lastUpdated":1779015790000}`),n={name:"mcp/broker.md"};function i(r,e,l,c,h,d){return t(),a("div",null,[...e[0]||(e[0]=[s(`<h1 id="the-broker-daemon" tabindex="-1">The broker daemon <a class="header-anchor" href="#the-broker-daemon" aria-label="Permalink to &quot;The broker daemon&quot;">​</a></h1><p><code>muhaven-broker</code> is a long-lived per-user daemon that holds two things you don&#39;t want in your LLM&#39;s process memory:</p><ol><li><strong>Your scoped JWT</strong> (<code>mcp.read.*</code> + <code>mcp.propose.*</code> claims) — issued at login, stored in OS keychain.</li><li><strong>Your ZeroDev session-key private half</strong> — used to sign UserOp authorizations.</li></ol><p>The MCP server (<code>muhaven-mcp</code>) talks to the broker over a <strong>Unix socket</strong> (POSIX) or <strong>named pipe</strong> (Windows). The broker exposes one signing primitive (<code>sign_hash</code>) and one JWT-store primitive (<code>store_jwt</code> / <code>get_jwt</code> / <code>clear_jwt</code>). It never speaks TCP.</p><h2 id="why-a-separate-process" tabindex="-1">Why a separate process? <a class="header-anchor" href="#why-a-separate-process" aria-label="Permalink to &quot;Why a separate process?&quot;">​</a></h2><p>Three threat-model wins:</p><ol><li><strong>LLM jailbreak ≠ key theft.</strong> A compromised LLM process — even one with arbitrary code execution via a CurXecute-style RCE — cannot read your keys from the broker&#39;s memory. To exfil, the attacker also needs to compromise a separate process running under your user with no inbound network surface.</li><li><strong>No env-block credentials.</strong> Putting a session key in <code>claude_desktop_config.json</code> env block is a known exfiltration class (R-7 in the threat model). The broker pattern keeps the key in OS keychain (or a 0600-mode file) instead.</li><li><strong>POSIX file-perm ACLs are simple and reviewable.</strong> Parent dir at <code>0700</code>, socket at <code>0600</code>. No TLS handshake, no auth tokens — the OS handles authorization.</li></ol><h2 id="lifecycle" tabindex="-1">Lifecycle <a class="header-anchor" href="#lifecycle" aria-label="Permalink to &quot;Lifecycle&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ muhaven-broker</span></span>
<span class="line"><span>  [12:01] broker: keystore  = ~/Library/Keychains/login.keychain (macOS)</span></span>
<span class="line"><span>  [12:01] broker: socket    = /tmp/muhaven-broker.sock</span></span>
<span class="line"><span>  [12:01] broker: backend   = https://api.muhaven.app</span></span>
<span class="line"><span>  [12:01] broker: listening</span></span></code></pre></div><p>The broker stays running. It survives terminal close (it&#39;s not tied to a TTY), but it&#39;s not a system service — when you reboot, you start it again.</p><p>To stop: <strong>Ctrl-C in the broker terminal</strong>, or send SIGTERM with <code>kill &lt;pid&gt;</code> from anywhere.</p><h2 id="authentication-the-device-code-flow" tabindex="-1">Authentication: the device-code flow <a class="header-anchor" href="#authentication-the-device-code-flow" aria-label="Permalink to &quot;Authentication: the device-code flow&quot;">​</a></h2><p>When you run <code>muhaven-broker login</code>:</p><ol><li>Broker hits <code>POST /api/v1/auth/device/code</code> → receives <code>{ device_code, user_code, verification_uri, expires_in, interval }</code>.</li><li>Broker prints <code>Open https://muhaven.app/link?code=ABCD-1234</code> and opens your default browser.</li><li>The <code>/link</code> Vue page <strong>fetches the requester metadata BEFORE you authorize</strong>. You see: &quot;A device named &#39;muhaven-broker&#39; on &#39;your-machine&#39; is requesting <code>mcp.read.*</code> + <code>mcp.propose.*</code> scopes.&quot;</li><li>You authorize with your passkey (the dashboard JWT auth path).</li><li>Broker polls <code>POST /api/v1/auth/device/token</code> every <code>interval</code> seconds.</li><li>On approval, backend returns a scoped JWT. Broker stores it in OS keychain.</li></ol><p>The pre-authorization fetch of the requester metadata is the load-bearing <strong>phishing-resistance</strong> control. A phishing site at <code>muhaven-link.com</code> cannot complete the ceremony because the <code>verification_uri</code> is hard-coded to <code>muhaven.app</code> and the WebAuthn passkey is RP-ID-pinned to <code>muhaven.app</code>.</p><h2 id="storage-os-keychain-with-file-fallback" tabindex="-1">Storage: OS keychain (with file fallback) <a class="header-anchor" href="#storage-os-keychain-with-file-fallback" aria-label="Permalink to &quot;Storage: OS keychain (with file fallback)&quot;">​</a></h2><p>Default backend (<code>@napi-rs/keyring</code>):</p><table tabindex="0"><thead><tr><th>Platform</th><th>Backed by</th></tr></thead><tbody><tr><td>macOS</td><td>Keychain Access (login keychain)</td></tr><tr><td>Linux</td><td>Secret Service (libsecret + GNOME Keyring / KWallet)</td></tr><tr><td>Windows</td><td>Credential Manager</td></tr></tbody></table><p>If the keychain isn&#39;t available (WSL2, devcontainer, SSH-remote shell), set <code>MUHAVEN_KEYRING=file</code> to use a 0600-mode file at <code>~/.muhaven/jwt.json</code>. The file is:</p><ul><li>Created with <code>umask(0077)</code> so only the owner can read it.</li><li>Parent directory created at <code>0700</code>.</li><li>Cleared on <code>muhaven-broker logout</code> (overwritten with <code>{}</code> and then removed).</li></ul><h2 id="the-ipc-protocol" tabindex="-1">The IPC protocol <a class="header-anchor" href="#the-ipc-protocol" aria-label="Permalink to &quot;The IPC protocol&quot;">​</a></h2><p>v0.2.0 of the broker protocol uses <strong>newline-delimited JSON</strong> over the socket:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>client → broker:  {&quot;verb&quot;:&quot;hello&quot;,&quot;client&quot;:&quot;muhaven-mcp&quot;,&quot;version&quot;:&quot;0.1.2&quot;}\\n</span></span>
<span class="line"><span>broker → client:  {&quot;ok&quot;:true,&quot;broker_version&quot;:&quot;0.1.2&quot;,&quot;caps&quot;:[&quot;sign_hash&quot;,&quot;jwt&quot;]}\\n</span></span>
<span class="line"><span></span></span>
<span class="line"><span>client → broker:  {&quot;verb&quot;:&quot;sign_hash&quot;,&quot;hash&quot;:&quot;0xabc...&quot;,&quot;domain&quot;:&quot;muhaven.placeholder.intent.v0:...&quot;}\\n</span></span>
<span class="line"><span>broker → client:  {&quot;ok&quot;:true,&quot;signature&quot;:&quot;0xdef...&quot;}\\n</span></span></code></pre></div><p><strong>Defensive properties:</strong></p><ul><li>Single-shot per connection — the broker doesn&#39;t pipeline. After response, it disconnects.</li><li>Size cap on inbound messages (16 KB).</li><li>Malformed JSON returns a structured <code>{&quot;ok&quot;:false,&quot;reason&quot;:&quot;PARSE_ERROR&quot;}</code> instead of crashing.</li><li>The connecting peer is verified via POSIX peer credentials (<code>SO_PEERCRED</code> on Linux) — only the broker-owning UID can connect.</li></ul><h2 id="muhaven-broker-subcommands" tabindex="-1"><code>muhaven-broker</code> subcommands <a class="header-anchor" href="#muhaven-broker-subcommands" aria-label="Permalink to &quot;\`muhaven-broker\` subcommands&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">muhaven-broker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                 # one-shot: env defaults + key + detached daemon + login</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">muhaven-broker</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                       # start the broker attached (no subcommand = daemon mode)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">muhaven-broker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                 # device-code flow only</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">muhaven-broker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logout</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # clear JWT from keystore</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">muhaven-broker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # print environment + keystore + reachability report</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">muhaven-broker</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --help</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # show usage</span></span></code></pre></div><p><code>setup</code> is the easy path for fresh installs (added in 0.1.4). Flags worth knowing:</p><ul><li><code>muhaven-broker setup --foreground</code> (<code>-f</code>) — run the daemon attached to the current shell instead of spawning it detached. Useful when a process supervisor will own the lifecycle.</li><li><code>muhaven-broker setup --skip-login</code> — spawn + return without minting a JWT (defer the login step).</li><li><code>muhaven-broker setup --no-launch-browser</code> — print the <code>/link</code> URL without trying to open it (handy on headless / SSH boxes).</li><li><code>muhaven-broker setup --backend-base-url &lt;URL&gt;</code> / <code>--dashboard-base-url &lt;URL&gt;</code> — explicit overrides (mirrors <code>login</code>&#39;s same flags).</li></ul><p>To stop a running daemon: Ctrl-C in its terminal if attached, or <code>kill &lt;pid&gt;</code> from anywhere if <code>setup</code> spawned it detached (PID is printed in the closing summary).</p><div class="tip custom-block"><p class="custom-block-title">Run <code>muhaven-broker doctor</code> first</p><p>For any &quot;auth broken&quot; issue, <code>doctor</code> is the first thing to run. It prints:</p><ul><li>Broker version + socket path</li><li>Keystore backend (keychain / file) + location</li><li>JWT presence, scopes, expiry</li><li>Backend URL + last reachable timestamp</li></ul></div><h2 id="why-the-placeholder-intent-domain" tabindex="-1">Why the placeholder intent domain? <a class="header-anchor" href="#why-the-placeholder-intent-domain" aria-label="Permalink to &quot;Why the placeholder intent domain?&quot;">​</a></h2><p>The broker&#39;s <code>sign_hash</code> verb signs <strong>only</strong> hashes prefixed with <code>muhaven.placeholder.intent.v0:</code>. The MCP server constructs these hashes from the propose-tool payload; the placeholder domain ensures a broker signature can <strong>never</strong> be replayed as a real EIP-712 hash or a real ZeroDev UserOp hash on-chain.</p><p>This means: a leaked broker signature isn&#39;t a &quot;drain my account&quot; key. It&#39;s only useful inside the MCP propose-then-commit ceremony, and only for one specific propose envelope.</p><p>The signature pattern is intentionally analogous to the WebAuthn challenge-binding pattern — single-use, scoped to one event, deterministic.</p><h2 id="where-next" tabindex="-1">Where next <a class="header-anchor" href="#where-next" aria-label="Permalink to &quot;Where next&quot;">​</a></h2><ul><li><a href="/mcp/install">Install</a> — get the broker running.</li><li><a href="/mcp/troubleshooting">Troubleshooting</a> — broker-specific issues.</li><li><a href="/policy/session-keys">Session keys</a> — how the broker fits the session-key model.</li></ul>`,37)])])}const k=o(n,[["render",i]]);export{u as __pageData,k as default};
